{
  "name": "MindfulBreather - Entrenador de Respiración",
  "description": "Una aplicación de entrenamiento de respiración guiada con visualizaciones sincronizadas, sonido de segundero y seguimiento de progreso para mejorar el bienestar.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Screen {
  SETUP = 'SETUP',
  CALIBRATION = 'CALIBRATION',
  SESSION = 'SESSION',
  SUMMARY = 'SUMMARY'
}

export enum Phase {
  INHALE = 'INHALE',
  EXHALE = 'EXHALE',
  HOLD = 'HOLD'
}

export interface BreathConfig {
  inhale: number;
  exhale: number;
  hold: number;
  duration: number | 'free';
  amplitude: number; // 0 to 1
}

export interface Preset {
  id: string;
  name: string;
  inhale: number;
  exhale: number;
  hold: number;
}

export interface SessionRecord {
  id: string;
  date: string;
  config: BreathConfig;
  totalTime: number;
  tension: number;
  comfort: 'Fácil' | 'Media' | 'Difícil';
}

export interface Preferences {
  darkMode: boolean;
  highContrast: boolean;
  reduceMotion: boolean;
  audioVolume: number;
  isMuted: boolean;
  silentMode: boolean;
}

import { Preset } from './types';

export const BREATH_PRESETS: Preset[] = [
  { id: 'calmar', name: 'Calmar', inhale: 4, exhale: 6, hold: 0 },
  { id: 'enfocar', name: 'Enfocar', inhale: 4, exhale: 4, hold: 0 },
  { id: 'dormir', name: 'Dormir', inhale: 4, exhale: 6, hold: 2 },
  { id: 'recuperar', name: 'Recuperar', inhale: 5, exhale: 5, hold: 0 },
];

export const MICRO_TIPS = [
  "Mandíbula suelta",
  "Hombros pesados",
  "Exhalación larga y suave",
  "Respirá silencioso por nariz",
  "Siente el aire entrar fresco",
  "Suelta la tensión con cada exhalación",
  "Columna recta pero relajada",
  "Enfócate en el ritmo"
];

export const DURATIONS = [2, 5, 10, 'free'];

export class AudioService {
  private context: AudioContext | null = null;
  private volume: number = 0.5;
  private isMuted: boolean = false;
  private isSilent: boolean = false;

  constructor() {
    // Context is initialized on first user interaction
  }

  private initContext() {
    if (!this.context) {
      this.context = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.context.state === 'suspended') {
      this.context.resume();
    }
  }

  updateSettings(volume: number, isMuted: boolean, isSilent: boolean) {
    this.volume = volume;
    this.isMuted = isMuted;
    this.isSilent = isSilent;
  }

  playClick() {
    if (this.isMuted || this.isSilent) return;

    this.initContext();
    if (!this.context) return;

    const osc = this.context.createOscillator();
    const gain = this.context.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(440, this.context.currentTime);
    osc.frequency.exponentialRampToValueAtTime(110, this.context.currentTime + 0.05);

    gain.gain.setValueAtTime(this.volume * 0.1, this.context.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.context.currentTime + 0.05);

    osc.connect(gain);
    gain.connect(this.context.destination);

    osc.start();
    osc.stop(this.context.currentTime + 0.05);
  }
}

export const audioService = new AudioService();

import React, { useEffect, useRef } from 'react';
import { Phase } from '../types';

interface WaveCanvasProps {
  phase: Phase;
  progress: number;
  inhaleTime: number;
  exhaleTime: number;
  holdTime: number;
  reduceMotion: boolean;
}

const WaveCanvas: React.FC<WaveCanvasProps> = ({ 
  phase, 
  progress, 
  inhaleTime, 
  exhaleTime, 
  holdTime,
  reduceMotion 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const draw = () => {
      const { width, height } = canvas;
      ctx.clearRect(0, 0, width, height);

      if (reduceMotion) {
          // Simplistic static-ish view for reduced motion
          ctx.beginPath();
          ctx.lineWidth = 4;
          ctx.strokeStyle = '#94a3b8';
          ctx.moveTo(50, height/2);
          ctx.lineTo(width - 50, height/2);
          ctx.stroke();

          const dotX = 50 + (width - 100) * (phase === Phase.INHALE ? progress * 0.4 : phase === Phase.EXHALE ? 0.4 + progress * 0.4 : 0.8 + progress * 0.2);
          ctx.beginPath();
          ctx.fillStyle = '#3b82f6';
          ctx.arc(dotX, height/2, 10, 0, Math.PI * 2);
          ctx.fill();
          return;
      }

      const totalTime = inhaleTime + exhaleTime + holdTime;
      const centerY = height / 2;
      const amplitude = height * 0.35;

      // Draw sine wave path
      ctx.beginPath();
      ctx.lineWidth = 3;
      ctx.strokeStyle = '#cbd5e1';
      ctx.setLineDash([5, 5]);

      for (let x = 0; x <= width; x++) {
        const t = (x / width) * totalTime;
        let y = centerY;

        if (t < inhaleTime) {
          // Inhale: Valley to Peak
          const phaseProgress = t / inhaleTime;
          y = centerY + amplitude * Math.cos(Math.PI * (phaseProgress + 1));
        } else if (t < inhaleTime + exhaleTime) {
          // Exhale: Peak to Valley
          const phaseProgress = (t - inhaleTime) / exhaleTime;
          y = centerY + amplitude * Math.cos(Math.PI * phaseProgress);
        } else {
          // Hold: Stay at Valley
          y = centerY + amplitude;
        }

        if (x === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      }
      ctx.stroke();
      ctx.setLineDash([]);

      // Calculate current position
      let currentX = 0;
      let currentY = centerY;

      if (phase === Phase.INHALE) {
        currentX = (progress * inhaleTime / totalTime) * width;
        currentY = centerY + amplitude * Math.cos(Math.PI * (progress + 1));
      } else if (phase === Phase.EXHALE) {
        currentX = ((inhaleTime + progress * exhaleTime) / totalTime) * width;
        currentY = centerY + amplitude * Math.cos(Math.PI * progress);
      } else {
        currentX = ((inhaleTime + exhaleTime + progress * holdTime) / totalTime) * width;
        currentY = centerY + amplitude;
      }

      // Draw indicator dot
      ctx.beginPath();
      ctx.shadowBlur = 10;
      ctx.shadowColor = '#3b82f6';
      ctx.fillStyle = '#3b82f6';
      ctx.arc(currentX, currentY, 8, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;
    };

    draw();
  }, [phase, progress, inhaleTime, exhaleTime, holdTime, reduceMotion]);

  return (
    <canvas 
      ref={canvasRef} 
      width={600} 
      height={150} 
      className="w-full max-w-2xl h-auto"
    />
  );
};

export default WaveCanvas;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Screen, Phase, BreathConfig, Preferences, SessionRecord } from './types';
import { BREATH_PRESETS, DURATIONS, MICRO_TIPS } from './constants';
import { audioService } from './services/AudioService';
import WaveCanvas from './components/WaveCanvas';

const App: React.FC = () => {
  // --- State ---
  const [screen, setScreen] = useState<Screen>(Screen.SETUP);
  const [config, setConfig] = useState<BreathConfig>({
    inhale: 4,
    exhale: 6,
    hold: 0,
    duration: 5,
    amplitude: 0.8
  });
  const [prefs, setPrefs] = useState<Preferences>({
    darkMode: false,
    highContrast: false,
    reduceMotion: false,
    audioVolume: 0.5,
    isMuted: false,
    silentMode: false
  });
  const [history, setHistory] = useState<SessionRecord[]>([]);

  // Runtime Session State
  const [phase, setPhase] = useState<Phase>(Phase.INHALE);
  const [progress, setProgress] = useState(0); // 0 to 1
  const [cycleCount, setCycleCount] = useState(0);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [tipIndex, setTipIndex] = useState(0);
  const [isActive, setIsActive] = useState(false);

  // Refs for logic
  const requestRef = useRef<number>();
  const startTimeRef = useRef<number>(0);
  const lastSecondRef = useRef<number>(0);
  const tipTimerRef = useRef<number>(0);

  // --- Persistence ---
  useEffect(() => {
    const savedHistory = localStorage.getItem('breath_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedPrefs = localStorage.getItem('breath_prefs');
    if (savedPrefs) setPrefs(JSON.parse(savedPrefs));
  }, []);

  useEffect(() => {
    localStorage.setItem('breath_prefs', JSON.stringify(prefs));
  }, [prefs]);

  useEffect(() => {
    audioService.updateSettings(prefs.audioVolume, prefs.isMuted, prefs.silentMode);
  }, [prefs.audioVolume, prefs.isMuted, prefs.silentMode]);

  // --- Logic ---

  const saveHistory = (record: SessionRecord) => {
    const newHistory = [record, ...history].slice(0, 10);
    setHistory(newHistory);
    localStorage.setItem('breath_history', JSON.stringify(newHistory));
  };

  const startSession = (isCalibration: boolean) => {
    setCycleCount(0);
    setPhase(Phase.INHALE);
    setProgress(0);
    setTipIndex(0);
    setIsActive(true);

    if (isCalibration) {
      setTimeLeft(30);
      setScreen(Screen.CALIBRATION);
    } else {
      setTimeLeft(config.duration === 'free' ? 0 : config.duration * 60);
      setScreen(Screen.SESSION);
    }

    startTimeRef.current = performance.now();
    lastSecondRef.current = 0;
    tipTimerRef.current = 0;
  };

  const update = useCallback((time: number) => {
    if (!isActive) return;

    if (!startTimeRef.current) startTimeRef.current = time;
    const elapsedTotal = (time - startTimeRef.current) / 1000;

    // Timer updates
    if (Math.floor(elapsedTotal) > lastSecondRef.current) {
        lastSecondRef.current = Math.floor(elapsedTotal);
        audioService.playClick();

        if (screen === Screen.CALIBRATION || (screen === Screen.SESSION && config.duration !== 'free')) {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    setIsActive(false);
                    return 0;
                }
                return prev - 1;
            });
        }

        // Microtip rotation
        tipTimerRef.current += 1;
        if (tipTimerRef.current >= 15) {
            tipTimerRef.current = 0;
            setTipIndex(prev => (prev + 1) % MICRO_TIPS.length);
        }
    }

    // Breathing phase logic
    const cycleTime = config.inhale + config.exhale + config.hold;
    const timeInCycle = elapsedTotal % cycleTime;

    // Ramp logic: first 3 cycles interpolate amplitude from 0.8x to 1x
    const cycleIndex = Math.floor(elapsedTotal / cycleTime);
    const rampFactor = cycleIndex < 3 ? 0.8 + (cycleIndex * 0.06) : 1.0;

    let currentPhase = Phase.INHALE;
    let phaseProgress = 0;

    if (timeInCycle < config.inhale) {
      currentPhase = Phase.INHALE;
      phaseProgress = timeInCycle / config.inhale;
    } else if (timeInCycle < config.inhale + config.exhale) {
      currentPhase = Phase.EXHALE;
      phaseProgress = (timeInCycle - config.inhale) / config.exhale;
    } else {
      currentPhase = Phase.HOLD;
      phaseProgress = (timeInCycle - config.inhale - config.exhale) / config.hold;
    }

    setPhase(currentPhase);
    setProgress(phaseProgress);
    setCycleCount(cycleIndex);

    requestRef.current = requestAnimationFrame(update);
  }, [isActive, config, screen]);

  useEffect(() => {
    if (isActive) {
      requestRef.current = requestAnimationFrame(update);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (timeLeft === 0 && screen === Screen.SESSION) {
          setScreen(Screen.SUMMARY);
      }
    }
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
  }, [isActive, update, timeLeft, screen]);

  // --- Handlers ---
  const handlePresetSelect = (preset: typeof BREATH_PRESETS[0]) => {
    setConfig(prev => ({ ...prev, inhale: preset.inhale, exhale: preset.exhale, hold: preset.hold }));
  };

  const adjustSpeed = (factor: number) => {
    setConfig(prev => ({
      ...prev,
      inhale: Math.max(2, Math.min(12, prev.inhale * factor)),
      exhale: Math.max(2, Math.min(12, prev.exhale * factor)),
      hold: prev.hold > 0 ? Math.max(0.5, Math.min(4, prev.hold * factor)) : 0
    }));
  };

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // --- Render Components ---

  const SetupView = () => (
    <div className="max-w-xl mx-auto p-6 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="text-center">
        <h1 className="text-4xl font-bold tracking-tight text-slate-900">MindfulBreather</h1>
        <p className="text-slate-500 mt-2">Encuentra tu centro, respira con calma.</p>
      </header>

      {/* Presets */}
      <section>
        <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 mb-4">Objetivo</h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {BREATH_PRESETS.map(p => (
            <button 
              key={p.id}
              onClick={() => handlePresetSelect(p)}
              className={`py-3 px-2 rounded-xl text-sm font-medium transition-all ${
                config.inhale === p.inhale && config.exhale === p.exhale && config.hold === p.hold
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-200 scale-105'
                : 'bg-white text-slate-600 border border-slate-200 hover:border-blue-300'
              }`}
            >
              {p.name}
              <div className="text-[10px] opacity-70">{p.inhale}/{p.exhale}/{p.hold}</div>
            </button>
          ))}
        </div>
      </section>

      {/* Manual Controls */}
      <section className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm space-y-6">
        <div className="grid grid-cols-3 gap-4">
          <div className="text-center">
            <label className="block text-xs text-slate-400 mb-1">Inhala</label>
            <input 
              type="number" step="0.5" value={config.inhale} 
              onChange={e => setConfig({...config, inhale: parseFloat(e.target.value) || 2})}
              className="w-full bg-slate-50 rounded-lg p-2 text-center font-bold border border-slate-200"
            />
          </div>
          <div className="text-center">
            <label className="block text-xs text-slate-400 mb-1">Exhala</label>
            <input 
              type="number" step="0.5" value={config.exhale} 
              onChange={e => setConfig({...config, exhale: parseFloat(e.target.value) || 2})}
              className="w-full bg-slate-50 rounded-lg p-2 text-center font-bold border border-slate-200"
            />
          </div>
          <div className="text-center">
            <label className="block text-xs text-slate-400 mb-1">Pausa</label>
            <input 
              type="number" step="0.5" value={config.hold} 
              onChange={e => setConfig({...config, hold: parseFloat(e.target.value) || 0})}
              className="w-full bg-slate-50 rounded-lg p-2 text-center font-bold border border-slate-200"
            />
          </div>
        </div>

        <div>
          <label className="flex justify-between text-sm text-slate-500 mb-2">
            <span>Amplitud</span>
            <span className="font-medium">{Math.round(config.amplitude * 100)}%</span>
          </label>
          <input 
            type="range" min="0.5" max="1" step="0.05" value={config.amplitude}
            onChange={e => setConfig({...config, amplitude: parseFloat(e.target.value)})}
            className="w-full h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-blue-600"
          />
        </div>

        <div>
          <label className="block text-sm text-slate-500 mb-2">Duración (minutos)</label>
          <div className="flex gap-2">
            {DURATIONS.map(d => (
              <button
                key={d}
                onClick={() => setConfig({...config, duration: d as any})}
                className={`flex-1 py-2 rounded-lg text-sm transition-colors ${
                  config.duration === d ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                }`}
              >
                {d === 'free' ? 'Libre' : d}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Audio & Display Prefs */}
      <section className="grid grid-cols-2 gap-4">
        <div className="space-y-4">
          <label className="flex items-center space-x-2 text-sm text-slate-600 cursor-pointer">
            <input type="checkbox" checked={prefs.darkMode} onChange={e => setPrefs({...prefs, darkMode: e.target.checked})} />
            <span>Modo Oscuro</span>
          </label>
          <label className="flex items-center space-x-2 text-sm text-slate-600 cursor-pointer">
            <input type="checkbox" checked={prefs.highContrast} onChange={e => setPrefs({...prefs, highContrast: e.target.checked})} />
            <span>Alto Contraste</span>
          </label>
          <label className="flex items-center space-x-2 text-sm text-slate-600 cursor-pointer">
            <input type="checkbox" checked={prefs.reduceMotion} onChange={e => setPrefs({...prefs, reduceMotion: e.target.checked})} />
            <span>Reducir Movimiento</span>
          </label>
        </div>
        <div className="bg-white p-4 rounded-2xl border border-slate-100 flex flex-col justify-center">
          <label className="text-xs text-slate-400 mb-2 flex justify-between">
            <span>Audio</span>
            <span>{Math.round(prefs.audioVolume * 100)}%</span>
          </label>
          <input 
            type="range" min="0" max="1" step="0.01" value={prefs.audioVolume}
            onChange={e => setPrefs({...prefs, audioVolume: parseFloat(e.target.value)})}
            className="w-full accent-blue-600 mb-3"
          />
          <div className="flex gap-2">
            <button onClick={() => setPrefs({...prefs, isMuted: !prefs.isMuted})} className="text-xs bg-slate-50 px-2 py-1 rounded">
              {prefs.isMuted ? 'Unmute' : 'Mute'}
            </button>
            <button onClick={() => setPrefs({...prefs, silentMode: !prefs.silentMode})} className="text-xs bg-slate-50 px-2 py-1 rounded">
              {prefs.silentMode ? 'Con Click' : 'Silencioso'}
            </button>
          </div>
        </div>
      </section>

      <div className="flex flex-col sm:flex-row gap-4 pt-4">
        <button 
          onClick={() => startSession(true)}
          className="flex-1 py-4 px-6 rounded-2xl border-2 border-blue-100 text-blue-600 font-bold hover:bg-blue-50 transition-colors"
        >
          Calibrar
        </button>
        <button 
          onClick={() => startSession(false)}
          className="flex-1 py-4 px-6 rounded-2xl bg-blue-600 text-white font-bold shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all hover:scale-105 active:scale-95"
        >
          Comenzar
        </button>
      </div>

      {history.length > 0 && (
        <section className="pt-8">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 mb-4">Historial Reciente</h2>
          <div className="space-y-3">
            {history.map(h => (
              <div key={h.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex justify-between items-center text-sm shadow-sm">
                <div>
                  <div className="font-semibold">{new Date(h.date).toLocaleDateString()}</div>
                  <div className="text-slate-400 text-xs">Ritmo: {h.config.inhale}/{h.config.exhale}/{h.config.hold} • {h.totalTime}m</div>
                </div>
                <div className="flex items-center gap-3">
                    <span className={`px-2 py-1 rounded-full text-[10px] ${h.comfort === 'Fácil' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                        {h.comfort}
                    </span>
                    <button onClick={() => {
                        setConfig(h.config);
                    }} className="text-blue-600 font-bold hover:underline">Repetir</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );

  const CalibrationView = () => (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center space-y-12">
        <header>
            <h2 className="text-2xl font-bold">Modo Calibración</h2>
            <p className="text-slate-500 max-w-sm">Busca una respiración suave y sin esfuerzo. Ajusta el ritmo a tu comodidad.</p>
        </header>

        <BreathingCircle />

        <div className="w-full max-w-md space-y-6">
            <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
                <button onClick={() => adjustSpeed(1.1)} className="px-6 py-3 bg-slate-100 rounded-xl font-bold hover:bg-slate-200">Más lento</button>
                <div className="text-center">
                    <div className="text-xs text-slate-400">Ritmo Actual</div>
                    <div className="font-mono text-lg font-bold">{config.inhale}s / {config.exhale}s</div>
                </div>
                <button onClick={() => adjustSpeed(0.9)} className="px-6 py-3 bg-slate-100 rounded-xl font-bold hover:bg-slate-200">Más rápido</button>
            </div>

            <p className="text-xs text-slate-400 italic">"Si aparece hambre de aire, acorta la exhalación o baja la amplitud."</p>

            <div className="flex gap-4">
                <button onClick={() => setScreen(Screen.SETUP)} className="flex-1 py-4 border border-slate-200 rounded-2xl text-slate-600 font-medium">Volver</button>
                <button onClick={() => startSession(false)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-bold shadow-lg shadow-blue-200">Usar este ritmo</button>
            </div>
        </div>
    </div>
  );

  const SessionView = () => {
    const rampFactor = cycleCount < 3 ? 0.8 + (cycleCount * 0.06) : 1.0;
    const currentScale = phase === Phase.INHALE 
        ? 0.5 + (0.5 * config.amplitude * rampFactor * progress)
        : phase === Phase.EXHALE
        ? 0.5 + (0.5 * config.amplitude * rampFactor * (1 - progress))
        : 0.5;

    return (
        <div className="flex flex-col items-center justify-between min-h-screen p-6 text-center">
            <div className="w-full flex justify-between items-center">
                <div className="text-left">
                    <div className="text-xs text-slate-400 font-semibold uppercase tracking-widest">Ciclos</div>
                    <div className="text-2xl font-bold font-mono text-blue-600">{cycleCount}</div>
                </div>
                <div className="text-right">
                    <div className="text-xs text-slate-400 font-semibold uppercase tracking-widest">Tiempo</div>
                    <div className="text-2xl font-bold font-mono">{config.duration === 'free' ? '∞' : formatTime(timeLeft)}</div>
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center space-y-16 w-full">
                <div 
                    className="relative flex items-center justify-center transition-transform duration-100"
                    style={{ transform: `scale(${currentScale})` }}
                >
                    <div className="w-64 h-64 bg-blue-500 rounded-full opacity-20 animate-pulse absolute"></div>
                    <div className="w-64 h-64 bg-blue-600 rounded-full shadow-2xl shadow-blue-400 flex items-center justify-center">
                         <span className="text-white text-xl font-bold tracking-widest uppercase">
                             {phase === Phase.INHALE ? 'Inhala' : phase === Phase.EXHALE ? 'Exhala' : 'Pausa'}
                         </span>
                    </div>
                </div>

                <div className="w-full max-w-2xl px-4">
                    <WaveCanvas 
                        phase={phase} 
                        progress={progress} 
                        inhaleTime={config.inhale} 
                        exhaleTime={config.exhale} 
                        holdTime={config.hold}
                        reduceMotion={prefs.reduceMotion}
                    />
                </div>

                <p className="text-xl text-slate-600 font-medium h-8 italic animate-in fade-in duration-1000">
                    {MICRO_TIPS[tipIndex]}
                </p>
            </div>

            <div className="w-full flex gap-4 pt-8">
                <button 
                    onClick={() => setIsActive(!isActive)}
                    className="flex-1 py-4 bg-white border border-slate-200 rounded-2xl font-bold text-slate-600"
                >
                    {isActive ? 'Pausa' : 'Continuar'}
                </button>
                <button 
                    onClick={() => { setIsActive(false); setScreen(Screen.SETUP); }}
                    className="flex-1 py-4 bg-slate-100 rounded-2xl font-bold text-slate-500 hover:bg-slate-200"
                >
                    Salir
                </button>
            </div>
        </div>
    );
  }

  const SummaryView = () => {
      const [tension, setTension] = useState(5);
      const [comfort, setComfort] = useState<'Fácil' | 'Media' | 'Difícil'>('Media');

      const handleSave = () => {
          const record: SessionRecord = {
              id: Date.now().toString(),
              date: new Date().toISOString(),
              config,
              totalTime: config.duration === 'free' ? Math.floor(lastSecondRef.current / 60) : config.duration,
              tension,
              comfort
          };
          saveHistory(record);
          setScreen(Screen.SETUP);
      };

      return (
          <div className="max-w-md mx-auto min-h-screen flex flex-col items-center justify-center p-6 space-y-12 text-center animate-in zoom-in-95 duration-500">
              <div className="space-y-2">
                  <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                      </svg>
                  </div>
                  <h2 className="text-3xl font-bold">¡Bien hecho!</h2>
                  <p className="text-slate-500">Sesión completada con éxito.</p>
              </div>

              <div className="w-full space-y-8 bg-white p-8 rounded-3xl border border-slate-100 shadow-xl">
                  <div>
                      <label className="block text-sm font-medium text-slate-600 mb-4">¿Cómo calificarías tu tensión actual? (0-10)</label>
                      <input 
                        type="range" min="0" max="10" value={tension} 
                        onChange={e => setTension(parseInt(e.target.value))}
                        className="w-full accent-blue-600"
                      />
                      <div className="flex justify-between text-xs text-slate-400 mt-2">
                          <span>Relajado</span>
                          <span>{tension}</span>
                          <span>Tenso</span>
                      </div>
                  </div>

                  <div>
                      <label className="block text-sm font-medium text-slate-600 mb-4">¿Qué tan fácil fue seguir el ritmo?</label>
                      <div className="flex gap-2">
                          {['Fácil', 'Media', 'Difícil'].map(opt => (
                              <button
                                key={opt}
                                onClick={() => setComfort(opt as any)}
                                className={`flex-1 py-3 rounded-xl border-2 transition-all ${
                                    comfort === opt ? 'border-blue-600 bg-blue-50 text-blue-600 font-bold' : 'border-slate-100 text-slate-400'
                                }`}
                              >
                                  {opt}
                              </button>
                          ))}
                      </div>
                  </div>

                  <button 
                    onClick={handleSave}
                    className="w-full py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all"
                  >
                      Guardar y Finalizar
                  </button>
              </div>
          </div>
      );
  }

  // Sub-component for logic visualization
  const BreathingCircle = () => {
    const rampFactor = cycleCount < 3 ? 0.8 + (cycleCount * 0.06) : 1.0;
    const currentScale = phase === Phase.INHALE 
        ? 0.5 + (0.5 * config.amplitude * rampFactor * progress)
        : phase === Phase.EXHALE
        ? 0.5 + (0.5 * config.amplitude * rampFactor * (1 - progress))
        : 0.5;

    return (
        <div className="relative flex items-center justify-center transition-transform duration-100" style={{ transform: `scale(${currentScale})` }}>
            <div className="w-48 h-48 bg-blue-100 rounded-full flex items-center justify-center border-4 border-blue-500">
                <span className="text-blue-600 font-bold uppercase tracking-widest text-sm">
                    {phase === Phase.INHALE ? 'Inhalar' : phase === Phase.EXHALE ? 'Exhalar' : 'Pausa'}
                </span>
            </div>
        </div>
    );
  };

  return (
    <div className={`min-h-screen ${prefs.darkMode ? 'bg-slate-900 text-slate-100' : 'bg-slate-50 text-slate-900'} ${prefs.highContrast ? 'high-contrast' : ''}`}>
      <main className="container mx-auto max-w-4xl min-h-screen">
        {screen === Screen.SETUP && <SetupView />}
        {screen === Screen.CALIBRATION && <CalibrationView />}
        {screen === Screen.SESSION && <SessionView />}
        {screen === Screen.SUMMARY && <SummaryView />}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Screen, Phase, BreathConfig, Preferences, SessionRecord } from './types';
import { BREATH_PRESETS, DURATIONS, MICRO_TIPS } from './constants';
import { audioService } from './services/AudioService';
import WaveCanvas from './components/WaveCanvas';

const App: React.FC = () => {
  // --- State ---
  const [screen, setScreen] = useState<Screen>(Screen.SETUP);
  const [config, setConfig] = useState<BreathConfig>({
    inhale: 4,
    exhale: 6,
    hold: 0,
    duration: 5,
    amplitude: 0.8
  });
  const [prefs, setPrefs] = useState<Preferences>({
    darkMode: false,
    highContrast: false,
    reduceMotion: false,
    audioVolume: 0.5,
    isMuted: false,
    silentMode: false
  });
  const [history, setHistory] = useState<SessionRecord[]>([]);

  // Runtime Session State
  const [phase, setPhase] = useState<Phase>(Phase.INHALE);
  const [progress, setProgress] = useState(0);
  const [cycleCount, setCycleCount] = useState(0);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [tipIndex, setTipIndex] = useState(0);
  const [isActive, setIsActive] = useState(false);

  // Refs for logic
  const requestRef = useRef<number>();
  const lastFrameTimeRef = useRef<number>(0);
  const accumulatedTimeRef = useRef<number>(0);
  const lastSecondEmittedRef = useRef<number>(-1);
  const tipTimerRef = useRef<number>(0);

  // --- Theme Classes ---
  const theme = {
    bg: prefs.darkMode ? 'bg-slate-950' : 'bg-slate-50',
    card: prefs.darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100',
    input: prefs.darkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200 text-slate-900',
    textMain: prefs.darkMode ? 'text-slate-100' : 'text-slate-900',
    textDim: prefs.darkMode ? 'text-slate-500' : 'text-slate-400',
    btnSecondary: prefs.darkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200',
    border: prefs.darkMode ? 'border-slate-800' : 'border-slate-100'
  };

  // --- Persistence ---
  useEffect(() => {
    const savedHistory = localStorage.getItem('breath_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedPrefs = localStorage.getItem('breath_prefs');
    if (savedPrefs) setPrefs(JSON.parse(savedPrefs));
  }, []);

  useEffect(() => {
    localStorage.setItem('breath_prefs', JSON.stringify(prefs));
  }, [prefs]);

  useEffect(() => {
    audioService.updateSettings(prefs.audioVolume, prefs.isMuted, prefs.silentMode);
  }, [prefs.audioVolume, prefs.isMuted, prefs.silentMode]);

  // --- Logic ---

  const saveHistory = (record: SessionRecord) => {
    const newHistory = [record, ...history].slice(0, 10);
    setHistory(newHistory);
    localStorage.setItem('breath_history', JSON.stringify(newHistory));
  };

  const startSession = (isCalibration: boolean) => {
    setCycleCount(0);
    setPhase(Phase.INHALE);
    setProgress(0);
    setTipIndex(0);

    if (isCalibration) {
      setTimeLeft(30);
      setScreen(Screen.CALIBRATION);
    } else {
      setTimeLeft(config.duration === 'free' ? 0 : config.duration * 60);
      setScreen(Screen.SESSION);
    }

    accumulatedTimeRef.current = 0;
    lastFrameTimeRef.current = 0;
    lastSecondEmittedRef.current = -1;
    tipTimerRef.current = 0;
    setIsActive(true);
  };

  const stopSession = () => {
    setIsActive(false);
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    setScreen(Screen.SETUP);
  };

  const update = useCallback((time: number) => {
    if (!isActive) {
      lastFrameTimeRef.current = 0;
      return;
    }

    if (!lastFrameTimeRef.current) {
      lastFrameTimeRef.current = time;
    }

    const deltaTime = (time - lastFrameTimeRef.current) / 1000;
    lastFrameTimeRef.current = time;
    accumulatedTimeRef.current += deltaTime;

    const elapsedTotal = accumulatedTimeRef.current;

    // Timer updates
    const currentSecond = Math.floor(elapsedTotal);
    if (currentSecond > lastSecondEmittedRef.current) {
        lastSecondEmittedRef.current = currentSecond;
        audioService.playClick();

        if (screen === Screen.CALIBRATION || (screen === Screen.SESSION && config.duration !== 'free')) {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    setIsActive(false);
                    return 0;
                }
                return prev - 1;
            });
        }

        tipTimerRef.current += 1;
        if (tipTimerRef.current >= 15) {
            tipTimerRef.current = 0;
            setTipIndex(prev => (prev + 1) % MICRO_TIPS.length);
        }
    }

    // Breathing phase logic
    const cycleTime = config.inhale + config.exhale + config.hold;
    const timeInCycle = elapsedTotal % cycleTime;
    const cycleIndex = Math.floor(elapsedTotal / cycleTime);

    let currentPhase = Phase.INHALE;
    let phaseProgress = 0;

    if (timeInCycle < config.inhale) {
      currentPhase = Phase.INHALE;
      phaseProgress = timeInCycle / config.inhale;
    } else if (timeInCycle < config.inhale + config.exhale) {
      currentPhase = Phase.EXHALE;
      phaseProgress = (timeInCycle - config.inhale) / config.exhale;
    } else {
      currentPhase = Phase.HOLD;
      phaseProgress = (timeInCycle - config.inhale - config.exhale) / config.hold;
    }

    setPhase(currentPhase);
    setProgress(phaseProgress);
    setCycleCount(cycleIndex);

    requestRef.current = requestAnimationFrame(update);
  }, [isActive, config, screen]);

  useEffect(() => {
    if (isActive) {
      requestRef.current = requestAnimationFrame(update);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (timeLeft === 0 && screen === Screen.SESSION && accumulatedTimeRef.current > 0) {
          setScreen(Screen.SUMMARY);
      }
    }
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
  }, [isActive, update, timeLeft, screen]);

  // --- Handlers ---
  const handlePresetSelect = (preset: typeof BREATH_PRESETS[0]) => {
    setConfig(prev => ({ ...prev, inhale: preset.inhale, exhale: preset.exhale, hold: preset.hold }));
  };

  const adjustSpeed = (factor: number) => {
    setConfig(prev => ({
      ...prev,
      inhale: Math.max(2, Math.min(12, prev.inhale * factor)),
      exhale: Math.max(2, Math.min(12, prev.exhale * factor)),
      hold: prev.hold > 0 ? Math.max(0.5, Math.min(4, prev.hold * factor)) : 0
    }));
  };

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // --- Render Components ---

  const SetupView = () => (
    <div className={`max-w-xl mx-auto p-6 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500`}>
      <header className="text-center">
        <h1 className={`text-4xl font-bold tracking-tight ${theme.textMain}`}>MindfulBreather</h1>
        <p className={`${theme.textDim} mt-2`}>Encuentra tu centro, respira con calma.</p>
      </header>

      {/* Presets */}
      <section>
        <h2 className="text-xs font-semibold uppercase tracking-wider text-slate-500 mb-4">Objetivo</h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {BREATH_PRESETS.map(p => {
            const isSelected = config.inhale === p.inhale && config.exhale === p.exhale && config.hold === p.hold;
            return (
              <button 
                key={p.id}
                onClick={() => handlePresetSelect(p)}
                className={`py-3 px-2 rounded-xl text-sm font-medium transition-all ${
                  isSelected
                  ? 'bg-blue-600 text-white shadow-xl shadow-blue-500/20 scale-105'
                  : `${theme.card} ${theme.textDim} border hover:border-blue-400`
                }`}
              >
                {p.name}
                <div className="text-[10px] opacity-70">{p.inhale}/{p.exhale}/{p.hold}</div>
              </button>
            );
          })}
        </div>
      </section>

      {/* Manual Controls */}
      <section className={`${theme.card} p-6 rounded-3xl border shadow-sm space-y-6`}>
        <div className="grid grid-cols-3 gap-4">
          <div className="text-center">
            <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">Inhala</label>
            <input 
              type="number" step="0.5" value={config.inhale} 
              onChange={e => setConfig({...config, inhale: parseFloat(e.target.value) || 2})}
              className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`}
            />
          </div>
          <div className="text-center">
            <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">Exhala</label>
            <input 
              type="number" step="0.5" value={config.exhale} 
              onChange={e => setConfig({...config, exhale: parseFloat(e.target.value) || 2})}
              className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`}
            />
          </div>
          <div className="text-center">
            <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">Pausa</label>
            <input 
              type="number" step="0.5" value={config.hold} 
              onChange={e => setConfig({...config, hold: parseFloat(e.target.value) || 0})}
              className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`}
            />
          </div>
        </div>

        <div>
          <label className="flex justify-between text-sm text-slate-500 mb-2">
            <span>Amplitud</span>
            <span className="font-bold">{Math.round(config.amplitude * 100)}%</span>
          </label>
          <input 
            type="range" min="0.5" max="1" step="0.05" value={config.amplitude}
            onChange={e => setConfig({...config, amplitude: parseFloat(e.target.value)})}
            className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-600"
          />
        </div>

        <div>
          <label className="block text-sm text-slate-500 mb-2">Duración (minutos)</label>
          <div className="flex gap-2">
            {DURATIONS.map(d => (
              <button
                key={d}
                onClick={() => setConfig({...config, duration: d as any})}
                className={`flex-1 py-2 rounded-lg text-sm transition-colors ${
                  config.duration === d 
                  ? 'bg-slate-800 dark:bg-slate-100 text-white dark:text-slate-900 font-bold' 
                  : `${theme.btnSecondary}`
                }`}
              >
                {d === 'free' ? 'Libre' : d}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Audio & Display Prefs */}
      <section className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className="space-y-4 px-2">
          <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
            <input type="checkbox" className="rounded" checked={prefs.darkMode} onChange={e => setPrefs({...prefs, darkMode: e.target.checked})} />
            <span>Modo Oscuro</span>
          </label>
          <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
            <input type="checkbox" className="rounded" checked={prefs.highContrast} onChange={e => setPrefs({...prefs, highContrast: e.target.checked})} />
            <span>Alto Contraste</span>
          </label>
          <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
            <input type="checkbox" className="rounded" checked={prefs.reduceMotion} onChange={e => setPrefs({...prefs, reduceMotion: e.target.checked})} />
            <span>Reducir Movimiento</span>
          </label>
        </div>
        <div className={`${theme.card} p-4 rounded-2xl border flex flex-col justify-center`}>
          <label className="text-xs text-slate-400 mb-2 flex justify-between">
            <span>Audio</span>
            <span className="font-bold">{Math.round(prefs.audioVolume * 100)}%</span>
          </label>
          <input 
            type="range" min="0" max="1" step="0.01" value={prefs.audioVolume}
            onChange={e => setPrefs({...prefs, audioVolume: parseFloat(e.target.value)})}
            className="w-full accent-blue-600 mb-3"
          />
          <div className="flex gap-2">
            <button onClick={() => setPrefs({...prefs, isMuted: !prefs.isMuted})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>
              {prefs.isMuted ? 'Unmute' : 'Mute'}
            </button>
            <button onClick={() => setPrefs({...prefs, silentMode: !prefs.silentMode})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>
              {prefs.silentMode ? 'Con Click' : 'Silencioso'}
            </button>
          </div>
        </div>
      </section>

      <div className="flex flex-col sm:flex-row gap-4 pt-4">
        <button 
          onClick={() => startSession(true)}
          className={`flex-1 py-4 px-6 rounded-2xl border-2 transition-all font-bold ${prefs.darkMode ? 'border-slate-800 text-slate-300 hover:bg-slate-900' : 'border-blue-100 text-blue-600 hover:bg-blue-50'}`}
        >
          Calibrar
        </button>
        <button 
          onClick={() => startSession(false)}
          className="flex-1 py-4 px-6 rounded-2xl bg-blue-600 text-white font-bold shadow-xl shadow-blue-500/30 hover:bg-blue-700 transition-all hover:scale-[1.02] active:scale-95"
        >
          Comenzar
        </button>
      </div>

      {history.length > 0 && (
        <section className="pt-8 pb-12">
          <h2 className="text-xs font-semibold uppercase tracking-wider text-slate-500 mb-4">Historial Reciente</h2>
          <div className="space-y-3">
            {history.map(h => (
              <div key={h.id} className={`${theme.card} p-4 rounded-2xl border flex justify-between items-center text-sm shadow-sm transition-transform hover:translate-x-1`}>
                <div>
                  <div className={`font-semibold ${theme.textMain}`}>{new Date(h.date).toLocaleDateString()}</div>
                  <div className={`${theme.textDim} text-xs uppercase tracking-tighter`}>Ritmo: {h.config.inhale}/{h.config.exhale}/{h.config.hold} • {h.totalTime}m</div>
                </div>
                <div className="flex items-center gap-3">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${h.comfort === 'Fácil' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400'}`}>
                        {h.comfort}
                    </span>
                    <button onClick={() => setConfig(h.config)} className="text-blue-500 font-bold hover:underline">Usar</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );

  const CalibrationView = () => (
    <div className={`flex flex-col items-center justify-center min-h-screen p-6 text-center space-y-12 ${theme.bg}`}>
        <header>
            <h2 className={`text-2xl font-bold ${theme.textMain}`}>Modo Calibración</h2>
            <p className={`${theme.textDim} max-w-sm`}>Busca una respiración suave y sin esfuerzo. Ajusta el ritmo a tu comodidad.</p>
        </header>

        <div className="flex-1 flex flex-col items-center justify-center">
          <BreathingCircle />
        </div>

        <div className="w-full max-w-md space-y-6">
            <div className={`${theme.card} flex justify-between items-center p-4 rounded-2xl shadow-sm border`}>
                <button onClick={() => adjustSpeed(1.1)} className={`px-6 py-3 rounded-xl font-bold ${theme.btnSecondary}`}>Más lento</button>
                <div className="text-center">
                    <div className="text-[10px] uppercase font-bold text-slate-500">Ritmo Actual</div>
                    <div className={`font-mono text-lg font-bold ${theme.textMain}`}>{config.inhale.toFixed(1)}s / {config.exhale.toFixed(1)}s</div>
                </div>
                <button onClick={() => adjustSpeed(0.9)} className={`px-6 py-3 rounded-xl font-bold ${theme.btnSecondary}`}>Más rápido</button>
            </div>

            <p className="text-xs text-slate-400 italic">"Si aparece hambre de aire, acorta la exhalación o baja la amplitud."</p>

            <div className="flex gap-4">
                <button onClick={() => stopSession()} className={`flex-1 py-4 border rounded-2xl font-medium ${theme.btnSecondary}`}>Volver</button>
                <button onClick={() => startSession(false)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-bold shadow-lg shadow-blue-500/20 hover:bg-blue-700">Comenzar Sesión</button>
            </div>
        </div>
    </div>
  );

  const SessionView = () => {
    return (
        <div className={`flex flex-col items-center justify-between min-h-screen p-6 text-center ${theme.bg}`}>
            <div className="w-full flex justify-between items-center">
                <div className="text-left">
                    <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Ciclos</div>
                    <div className="text-2xl font-bold font-mono text-blue-600">{cycleCount}</div>
                </div>
                <div className="text-right">
                    <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Restante</div>
                    <div className={`text-2xl font-bold font-mono ${theme.textMain}`}>{config.duration === 'free' ? '∞' : formatTime(timeLeft)}</div>
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center space-y-16 w-full">
                <BreathingCircle />

                <div className="w-full max-w-2xl px-4">
                    <WaveCanvas 
                        phase={phase} 
                        progress={progress} 
                        inhaleTime={config.inhale} 
                        exhaleTime={config.exhale} 
                        holdTime={config.hold}
                        reduceMotion={prefs.reduceMotion}
                    />
                </div>

                <div className="h-8 flex items-center justify-center">
                  <p className={`text-lg font-medium italic animate-in fade-in duration-1000 ${theme.textMain}`}>
                      {MICRO_TIPS[tipIndex]}
                  </p>
                </div>
            </div>

            <div className="w-full max-w-md flex gap-4 pt-8 pb-4">
                <button 
                    onClick={() => setIsActive(!isActive)}
                    className={`flex-1 py-4 rounded-2xl font-bold transition-all active:scale-95 ${isActive ? theme.btnSecondary : 'bg-blue-600 text-white shadow-lg shadow-blue-500/30'}`}
                >
                    {isActive ? 'Pausar' : 'Continuar'}
                </button>
                <button 
                    onClick={() => stopSession()}
                    className={`flex-1 py-4 rounded-2xl font-bold transition-all ${theme.btnSecondary}`}
                >
                    Salir
                </button>
            </div>
        </div>
    );
  }

  const SummaryView = () => {
      const [tension, setTension] = useState(5);
      const [comfort, setComfort] = useState<'Fácil' | 'Media' | 'Difícil'>('Media');

      const handleSave = () => {
          const record: SessionRecord = {
              id: Date.now().toString(),
              date: new Date().toISOString(),
              config,
              totalTime: config.duration === 'free' ? Math.max(1, Math.floor(accumulatedTimeRef.current / 60)) : config.duration,
              tension,
              comfort
          };
          saveHistory(record);
          setScreen(Screen.SETUP);
      };

      return (
          <div className={`max-w-md mx-auto min-h-screen flex flex-col items-center justify-center p-6 space-y-12 text-center animate-in zoom-in-95 duration-500 ${theme.bg}`}>
              <div className="space-y-2">
                  <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-full flex items-center justify-center mx-auto mb-4">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                      </svg>
                  </div>
                  <h2 className={`text-3xl font-bold ${theme.textMain}`}>¡Bien hecho!</h2>
                  <p className={theme.textDim}>Sesión completada con éxito.</p>
              </div>

              <div className={`w-full space-y-8 ${theme.card} p-8 rounded-3xl border shadow-xl`}>
                  <div>
                      <label className={`block text-sm font-medium ${theme.textMain} mb-4`}>¿Cómo calificarías tu tensión actual?</label>
                      <input 
                        type="range" min="0" max="10" value={tension} 
                        onChange={e => setTension(parseInt(e.target.value))}
                        className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-600"
                      />
                      <div className="flex justify-between text-[10px] font-bold uppercase text-slate-500 mt-2">
                          <span>Relajado</span>
                          <span className="text-blue-600 text-sm">{tension}</span>
                          <span>Tenso</span>
                      </div>
                  </div>

                  <div>
                      <label className={`block text-sm font-medium ${theme.textMain} mb-4`}>¿Qué tan fácil fue seguir el ritmo?</label>
                      <div className="flex gap-2">
                          {['Fácil', 'Media', 'Difícil'].map(opt => (
                              <button
                                key={opt}
                                onClick={() => setComfort(opt as any)}
                                className={`flex-1 py-3 rounded-xl border-2 transition-all ${
                                    comfort === opt 
                                    ? 'border-blue-600 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-bold' 
                                    : `${theme.card} ${theme.textDim}`
                                }`}
                              >
                                  {opt}
                              </button>
                          ))}
                      </div>
                  </div>

                  <button 
                    onClick={handleSave}
                    className="w-full py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-xl shadow-blue-500/20 hover:bg-blue-700 active:scale-95 transition-all"
                  >
                      Guardar y Finalizar
                  </button>
              </div>
          </div>
      );
  }

  // Sub-component for logic visualization
  const BreathingCircle = () => {
    const rampFactor = cycleCount < 3 ? 0.8 + (cycleCount * 0.06) : 1.0;
    const currentScale = phase === Phase.INHALE 
        ? 0.5 + (0.5 * config.amplitude * rampFactor * progress)
        : phase === Phase.EXHALE
        ? 0.5 + (0.5 * config.amplitude * rampFactor * (1 - progress))
        : 0.5;

    return (
        <div 
          className="relative flex items-center justify-center transition-transform duration-100 will-change-transform" 
          style={{ transform: `scale(${currentScale})` }}
        >
            <div className="w-64 h-64 bg-blue-600 rounded-full shadow-[0_0_60px_rgba(37,99,235,0.4)] flex items-center justify-center border-4 border-blue-400/30">
                <span className="text-white font-bold uppercase tracking-widest text-xl drop-shadow-md">
                    {phase === Phase.INHALE ? 'Inhala' : phase === Phase.EXHALE ? 'Exhala' : 'Pausa'}
                </span>
            </div>
            <div className="absolute w-72 h-72 bg-blue-400 rounded-full opacity-10 animate-ping"></div>
        </div>
    );
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${theme.bg}`}>
      <main className="container mx-auto max-w-4xl min-h-screen">
        {screen === Screen.SETUP && <SetupView />}
        {screen === Screen.CALIBRATION && <CalibrationView />}
        {screen === Screen.SESSION && <SessionView />}
        {screen === Screen.SUMMARY && <SummaryView />}
      </main>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import { Phase } from '../types';

interface WaveCanvasProps {
  phase: Phase;
  progress: number;
  inhaleTime: number;
  exhaleTime: number;
  holdTime: number;
  reduceMotion: boolean;
}

const WaveCanvas: React.FC<WaveCanvasProps> = ({ 
  phase, 
  progress, 
  inhaleTime, 
  exhaleTime, 
  holdTime,
  reduceMotion 
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const isDark = document.body.parentElement?.classList.contains('dark') || 
                  window.getComputedStyle(document.body).backgroundColor.includes('rgba(15, 23, 42') ||
                  window.getComputedStyle(document.body).backgroundColor.includes('rgb(2'); // Rough check for dark mode if not using classes

    // Better way: Check if our theme state implies dark mode. 
    // Since we don't have direct access to 'prefs.darkMode' easily here without prop drilling,
    // we use CSS variables or computed style.
    const computedStyle = window.getComputedStyle(canvas);
    const textColor = computedStyle.color === 'rgb(248, 250, 252)' || computedStyle.color === 'white' ? '#475569' : '#cbd5e1';

    const draw = () => {
      const { width, height } = canvas;
      ctx.clearRect(0, 0, width, height);

      if (reduceMotion) {
          ctx.beginPath();
          ctx.lineWidth = 4;
          ctx.strokeStyle = textColor;
          ctx.moveTo(50, height/2);
          ctx.lineTo(width - 50, height/2);
          ctx.stroke();

          const dotX = 50 + (width - 100) * (phase === Phase.INHALE ? progress * 0.4 : phase === Phase.EXHALE ? 0.4 + progress * 0.4 : 0.8 + progress * 0.2);
          ctx.beginPath();
          ctx.fillStyle = '#3b82f6';
          ctx.arc(dotX, height/2, 10, 0, Math.PI * 2);
          ctx.fill();
          return;
      }

      const totalTime = inhaleTime + exhaleTime + holdTime;
      const centerY = height / 2;
      const amplitude = height * 0.35;

      // Draw sine wave path
      ctx.beginPath();
      ctx.lineWidth = 3;
      ctx.strokeStyle = textColor;
      ctx.setLineDash([5, 5]);

      for (let x = 0; x <= width; x++) {
        const t = (x / width) * totalTime;
        let y = centerY;

        if (t < inhaleTime) {
          const phaseProgress = t / inhaleTime;
          y = centerY + amplitude * Math.cos(Math.PI * (phaseProgress + 1));
        } else if (t < inhaleTime + exhaleTime) {
          const phaseProgress = (t - inhaleTime) / exhaleTime;
          y = centerY + amplitude * Math.cos(Math.PI * phaseProgress);
        } else {
          y = centerY + amplitude;
        }

        if (x === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      }
      ctx.stroke();
      ctx.setLineDash([]);

      // Calculate current position
      let currentX = 0;
      let currentY = centerY;

      if (phase === Phase.INHALE) {
        currentX = (progress * inhaleTime / totalTime) * width;
        currentY = centerY + amplitude * Math.cos(Math.PI * (progress + 1));
      } else if (phase === Phase.EXHALE) {
        currentX = ((inhaleTime + progress * exhaleTime) / totalTime) * width;
        currentY = centerY + amplitude * Math.cos(Math.PI * progress);
      } else {
        currentX = ((inhaleTime + exhaleTime + progress * holdTime) / totalTime) * width;
        currentY = centerY + amplitude;
      }

      // Draw glow
      ctx.beginPath();
      ctx.shadowBlur = 15;
      ctx.shadowColor = 'rgba(59, 130, 246, 0.6)';
      ctx.fillStyle = '#3b82f6';
      ctx.arc(currentX, currentY, 10, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;
    };

    draw();
  }, [phase, progress, inhaleTime, exhaleTime, holdTime, reduceMotion]);

  return (
    <canvas 
      ref={canvasRef} 
      width={600} 
      height={150} 
      className="w-full max-w-2xl h-auto text-slate-100 dark:text-slate-600"
    />
  );
};

export default WaveCanvas;

export enum Screen {
  SETUP = 'SETUP',
  CALIBRATION = 'CALIBRATION',
  SESSION = 'SESSION',
  SUMMARY = 'SUMMARY'
}

export enum Phase {
  INHALE = 'INHALE',
  EXHALE = 'EXHALE',
  HOLD = 'HOLD'
}

export interface BreathConfig {
  inhale: number;
  exhale: number;
  hold: number;
  duration: number | 'free';
  amplitude: number; // 0 to 1
}

export interface Preset {
  id: string;
  name: string;
  inhale: number;
  exhale: number;
  hold: number;
}

export interface SessionRecord {
  id: string;
  date: string;
  config: BreathConfig;
  totalTime: number;
  tension: number;
  comfort: 'Fácil' | 'Media' | 'Difícil';
}

export interface Preferences {
  darkMode: boolean;
  reduceMotion: boolean;
  audioVolume: number;
  isMuted: boolean;
  silentMode: boolean;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Screen, Phase, BreathConfig, Preferences, SessionRecord } from './types';
import { BREATH_PRESETS, DURATIONS, MICRO_TIPS } from './constants';
import { audioService } from './services/AudioService';
import WaveCanvas from './components/WaveCanvas';

const App: React.FC = () => {
  // --- State ---
  const [screen, setScreen] = useState<Screen>(Screen.SETUP);
  const [config, setConfig] = useState<BreathConfig>({
    inhale: 4,
    exhale: 6,
    hold: 0,
    duration: 5,
    amplitude: 0.8
  });
  const [prefs, setPrefs] = useState<Preferences>({
    darkMode: false,
    reduceMotion: false,
    audioVolume: 0.5,
    isMuted: false,
    silentMode: false
  });
  const [history, setHistory] = useState<SessionRecord[]>([]);

  // Runtime Session State
  const [phase, setPhase] = useState<Phase>(Phase.INHALE);
  const [progress, setProgress] = useState(0);
  const [cycleCount, setCycleCount] = useState(0);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [tipIndex, setTipIndex] = useState(0);
  const [isActive, setIsActive] = useState(false);

  // Refs for logic
  const requestRef = useRef<number>();
  const lastFrameTimeRef = useRef<number>(0);
  const accumulatedTimeRef = useRef<number>(0);
  const lastSecondEmittedRef = useRef<number>(-1);
  const tipTimerRef = useRef<number>(0);

  // --- Theme Classes ---
  const theme = {
    bg: prefs.darkMode ? 'bg-slate-950' : 'bg-slate-50',
    card: prefs.darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100',
    input: prefs.darkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200 text-slate-900',
    textMain: prefs.darkMode ? 'text-slate-100' : 'text-slate-900',
    textDim: prefs.darkMode ? 'text-slate-500' : 'text-slate-400',
    btnSecondary: prefs.darkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200',
    border: prefs.darkMode ? 'border-slate-800' : 'border-slate-100'
  };

  // --- Persistence ---
  useEffect(() => {
    const savedHistory = localStorage.getItem('breath_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedPrefs = localStorage.getItem('breath_prefs');
    if (savedPrefs) setPrefs(JSON.parse(savedPrefs));
  }, []);

  useEffect(() => {
    localStorage.setItem('breath_prefs', JSON.stringify(prefs));
  }, [prefs]);

  useEffect(() => {
    audioService.updateSettings(prefs.audioVolume, prefs.isMuted, prefs.silentMode);
  }, [prefs.audioVolume, { isMuted: prefs.isMuted, silentMode: prefs.silentMode }]);

  // --- Logic ---

  const saveHistory = (record: SessionRecord) => {
    const newHistory = [record, ...history].slice(0, 10);
    setHistory(newHistory);
    localStorage.setItem('breath_history', JSON.stringify(newHistory));
  };

  const startSession = (isCalibration: boolean) => {
    setCycleCount(0);
    setPhase(Phase.INHALE);
    setProgress(0);
    setTipIndex(0);

    if (isCalibration) {
      setTimeLeft(30);
      setScreen(Screen.CALIBRATION);
    } else {
      setTimeLeft(config.duration === 'free' ? 0 : config.duration * 60);
      setScreen(Screen.SESSION);
    }

    accumulatedTimeRef.current = 0;
    lastFrameTimeRef.current = 0;
    lastSecondEmittedRef.current = -1;
    tipTimerRef.current = 0;
    setIsActive(true);
  };

  const stopSession = () => {
    setIsActive(false);
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    setScreen(Screen.SETUP);
  };

  const update = useCallback((time: number) => {
    if (!isActive) {
      lastFrameTimeRef.current = 0;
      return;
    }

    if (!lastFrameTimeRef.current) {
      lastFrameTimeRef.current = time;
    }

    const deltaTime = (time - lastFrameTimeRef.current) / 1000;
    lastFrameTimeRef.current = time;
    accumulatedTimeRef.current += deltaTime;

    const elapsedTotal = accumulatedTimeRef.current;

    // Timer updates
    const currentSecond = Math.floor(elapsedTotal);
    if (currentSecond > lastSecondEmittedRef.current) {
        lastSecondEmittedRef.current = currentSecond;
        audioService.playClick();

        if (screen === Screen.CALIBRATION || (screen === Screen.SESSION && config.duration !== 'free')) {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    setIsActive(false);
                    return 0;
                }
                return prev - 1;
            });
        }

        tipTimerRef.current += 1;
        if (tipTimerRef.current >= 15) {
            tipTimerRef.current = 0;
            setTipIndex(prev => (prev + 1) % MICRO_TIPS.length);
        }
    }

    // Breathing phase logic
    const cycleTime = config.inhale + config.exhale + config.hold;
    const timeInCycle = elapsedTotal % cycleTime;
    const cycleIndex = Math.floor(elapsedTotal / cycleTime);

    let currentPhase = Phase.INHALE;
    let phaseProgress = 0;

    if (timeInCycle < config.inhale) {
      currentPhase = Phase.INHALE;
      phaseProgress = timeInCycle / config.inhale;
    } else if (timeInCycle < config.inhale + config.exhale) {
      currentPhase = Phase.EXHALE;
      phaseProgress = (timeInCycle - config.inhale) / config.exhale;
    } else {
      currentPhase = Phase.HOLD;
      phaseProgress = (timeInCycle - config.inhale - config.exhale) / config.hold;
    }

    setPhase(currentPhase);
    setProgress(phaseProgress);
    setCycleCount(cycleIndex);

    requestRef.current = requestAnimationFrame(update);
  }, [isActive, config, screen]);

  useEffect(() => {
    if (isActive) {
      requestRef.current = requestAnimationFrame(update);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (timeLeft === 0 && screen === Screen.SESSION && accumulatedTimeRef.current > 0) {
          setScreen(Screen.SUMMARY);
      }
    }
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
  }, [isActive, update, timeLeft, screen]);

  // --- Handlers ---
  const handlePresetSelect = (preset: typeof BREATH_PRESETS[0]) => {
    setConfig(prev => ({ ...prev, inhale: preset.inhale, exhale: preset.exhale, hold: preset.hold }));
  };

  const adjustSpeed = (factor: number) => {
    setConfig(prev => ({
      ...prev,
      inhale: Math.max(2, Math.min(12, prev.inhale * factor)),
      exhale: Math.max(2, Math.min(12, prev.exhale * factor)),
      hold: prev.hold > 0 ? Math.max(0.5, Math.min(4, prev.hold * factor)) : 0
    }));
  };

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, '0')}`;
  };

  // --- Render Components ---

  const SetupView = () => (
    <div className={`max-w-xl mx-auto p-6 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500`}>
      <header className="text-center">
        <h1 className={`text-4xl font-bold tracking-tight ${theme.textMain}`}>MindfulBreather</h1>
        <p className={`${theme.textDim} mt-2`}>Encuentra tu centro, respira con calma.</p>
      </header>

      {/* Presets */}
      <section>
        <h2 className="text-xs font-semibold uppercase tracking-wider text-slate-500 mb-4">Objetivo</h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {BREATH_PRESETS.map(p => {
            const isSelected = config.inhale === p.inhale && config.exhale === p.exhale && config.hold === p.hold;
            return (
              <button 
                key={p.id}
                onClick={() => handlePresetSelect(p)}
                className={`py-3 px-2 rounded-xl text-sm font-medium transition-all ${
                  isSelected
                  ? 'bg-blue-600 text-white shadow-xl shadow-blue-500/20 scale-105'
                  : `${theme.card} ${theme.textDim} border hover:border-blue-400`
                }`}
              >
                {p.name}
                <div className="text-[10px] opacity-70">{p.inhale}/{p.exhale}/{p.hold}</div>
              </button>
            );
          })}
        </div>
      </section>

      {/* Manual Controls */}
      <section className={`${theme.card} p-6 rounded-3xl border shadow-sm space-y-6`}>
        <div className="grid grid-cols-3 gap-4">
          <div className="text-center">
            <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">Inhala</label>
            <input 
              type="number" step="0.5" value={config.inhale} 
              onChange={e => setConfig({...config, inhale: parseFloat(e.target.value) || 2})}
              className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`}
            />
          </div>
          <div className="text-center">
            <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">Exhala</label>
            <input 
              type="number" step="0.5" value={config.exhale} 
              onChange={e => setConfig({...config, exhale: parseFloat(e.target.value) || 2})}
              className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`}
            />
          </div>
          <div className="text-center">
            <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">Pausa</label>
            <input 
              type="number" step="0.5" value={config.hold} 
              onChange={e => setConfig({...config, hold: parseFloat(e.target.value) || 0})}
              className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`}
            />
          </div>
        </div>

        <div>
          <label className="flex justify-between text-sm text-slate-500 mb-2">
            <span>Amplitud</span>
            <span className="font-bold">{Math.round(config.amplitude * 100)}%</span>
          </label>
          <input 
            type="range" min="0.5" max="1" step="0.05" value={config.amplitude}
            onChange={e => setConfig({...config, amplitude: parseFloat(e.target.value)})}
            className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-600"
          />
        </div>

        <div>
          <label className="block text-sm text-slate-500 mb-2">Duración (minutos)</label>
          <div className="flex gap-2">
            {DURATIONS.map(d => (
              <button
                key={d}
                onClick={() => setConfig({...config, duration: d as any})}
                className={`flex-1 py-2 rounded-lg text-sm transition-colors ${
                  config.duration === d 
                  ? 'bg-slate-800 dark:bg-slate-100 text-white dark:text-slate-900 font-bold' 
                  : `${theme.btnSecondary}`
                }`}
              >
                {d === 'free' ? 'Libre' : d}
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Audio & Display Prefs */}
      <section className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className="space-y-4 px-2">
          <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
            <input type="checkbox" className="rounded" checked={prefs.darkMode} onChange={e => setPrefs({...prefs, darkMode: e.target.checked})} />
            <span>Modo Oscuro</span>
          </label>
          <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
            <input type="checkbox" className="rounded" checked={prefs.reduceMotion} onChange={e => setPrefs({...prefs, reduceMotion: e.target.checked})} />
            <span>Reducir Movimiento</span>
          </label>
        </div>
        <div className={`${theme.card} p-4 rounded-2xl border flex flex-col justify-center`}>
          <label className="text-xs text-slate-400 mb-2 flex justify-between">
            <span>Audio</span>
            <span className="font-bold">{Math.round(prefs.audioVolume * 100)}%</span>
          </label>
          <input 
            type="range" min="0" max="1" step="0.01" value={prefs.audioVolume}
            onChange={e => setPrefs({...prefs, audioVolume: parseFloat(e.target.value)})}
            className="w-full accent-blue-600 mb-3"
          />
          <div className="flex gap-2">
            <button onClick={() => setPrefs({...prefs, isMuted: !prefs.isMuted})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>
              {prefs.isMuted ? 'Unmute' : 'Mute'}
            </button>
            <button onClick={() => setPrefs({...prefs, silentMode: !prefs.silentMode})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>
              {prefs.silentMode ? 'Con Click' : 'Silencioso'}
            </button>
          </div>
        </div>
      </section>

      <div className="flex flex-col sm:flex-row gap-4 pt-4">
        <button 
          onClick={() => startSession(true)}
          className={`flex-1 py-4 px-6 rounded-2xl border-2 transition-all font-bold ${prefs.darkMode ? 'border-slate-800 text-slate-300 hover:bg-slate-900' : 'border-blue-100 text-blue-600 hover:bg-blue-50'}`}
        >
          Calibrar
        </button>
        <button 
          onClick={() => startSession(false)}
          className="flex-1 py-4 px-6 rounded-2xl bg-blue-600 text-white font-bold shadow-xl shadow-blue-500/30 hover:bg-blue-700 transition-all hover:scale-[1.02] active:scale-95"
        >
          Comenzar
        </button>
      </div>

      {history.length > 0 && (
        <section className="pt-8 pb-12">
          <h2 className="text-xs font-semibold uppercase tracking-wider text-slate-500 mb-4">Historial Reciente</h2>
          <div className="space-y-3">
            {history.map(h => (
              <div key={h.id} className={`${theme.card} p-4 rounded-2xl border flex justify-between items-center text-sm shadow-sm transition-transform hover:translate-x-1`}>
                <div>
                  <div className={`font-semibold ${theme.textMain}`}>{new Date(h.date).toLocaleDateString()}</div>
                  <div className={`${theme.textDim} text-xs uppercase tracking-tighter`}>Ritmo: {h.config.inhale}/{h.config.exhale}/{h.config.hold} • {h.totalTime}m</div>
                </div>
                <div className="flex items-center gap-3">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${h.comfort === 'Fácil' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400'}`}>
                        {h.comfort}
                    </span>
                    <button onClick={() => setConfig(h.config)} className="text-blue-500 font-bold hover:underline">Usar</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );

  const CalibrationView = () => (
    <div className={`flex flex-col items-center justify-center min-h-screen p-6 text-center space-y-12 ${theme.bg}`}>
        <header>
            <h2 className={`text-2xl font-bold ${theme.textMain}`}>Modo Calibración</h2>
            <p className={`${theme.textDim} max-w-sm`}>Busca una respiración suave y sin esfuerzo. Ajusta el ritmo a tu comodidad.</p>
        </header>

        <div className="flex-1 flex flex-col items-center justify-center">
          <BreathingCircle />
        </div>

        <div className="w-full max-w-md space-y-6">
            <div className={`${theme.card} flex justify-between items-center p-4 rounded-2xl shadow-sm border`}>
                <button onClick={() => adjustSpeed(1.1)} className={`px-6 py-3 rounded-xl font-bold ${theme.btnSecondary}`}>Más lento</button>
                <div className="text-center">
                    <div className="text-[10px] uppercase font-bold text-slate-500">Ritmo Actual</div>
                    <div className={`font-mono text-lg font-bold ${theme.textMain}`}>{config.inhale.toFixed(1)}s / {config.exhale.toFixed(1)}s</div>
                </div>
                <button onClick={() => adjustSpeed(0.9)} className={`px-6 py-3 rounded-xl font-bold ${theme.btnSecondary}`}>Más rápido</button>
            </div>

            <p className="text-xs text-slate-400 italic">"Si aparece hambre de aire, acorta la exhalación o baja la amplitud."</p>

            <div className="flex gap-4">
                <button onClick={() => stopSession()} className={`flex-1 py-4 border rounded-2xl font-medium ${theme.btnSecondary}`}>Volver</button>
                <button onClick={() => startSession(false)} className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-bold shadow-lg shadow-blue-500/20 hover:bg-blue-700">Comenzar Sesión</button>
            </div>
        </div>
    </div>
  );

  const SessionView = () => {
    return (
        <div className={`flex flex-col items-center justify-between min-h-screen p-6 text-center ${theme.bg}`}>
            <div className="w-full flex justify-between items-center">
                <div className="text-left">
                    <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Ciclos</div>
                    <div className="text-2xl font-bold font-mono text-blue-600">{cycleCount}</div>
                </div>
                <div className="text-right">
                    <div className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Restante</div>
                    <div className={`text-2xl font-bold font-mono ${theme.textMain}`}>{config.duration === 'free' ? '∞' : formatTime(timeLeft)}</div>
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center space-y-16 w-full">
                <BreathingCircle />

                <div className="w-full max-w-2xl px-4">
                    <WaveCanvas 
                        phase={phase} 
                        progress={progress} 
                        inhaleTime={config.inhale} 
                        exhaleTime={config.exhale} 
                        holdTime={config.hold}
                        reduceMotion={prefs.reduceMotion}
                    />
                </div>

                <div className="h-8 flex items-center justify-center">
                  <p className={`text-lg font-medium italic animate-in fade-in duration-1000 ${theme.textMain}`}>
                      {MICRO_TIPS[tipIndex]}
                  </p>
                </div>
            </div>

            <div className="w-full max-w-md flex gap-4 pt-8 pb-4">
                <button 
                    onClick={() => setIsActive(!isActive)}
                    className={`flex-1 py-4 rounded-2xl font-bold transition-all active:scale-95 ${isActive ? theme.btnSecondary : 'bg-blue-600 text-white shadow-lg shadow-blue-500/30'}`}
                >
                    {isActive ? 'Pausar' : 'Continuar'}
                </button>
                <button 
                    onClick={() => stopSession()}
                    className={`flex-1 py-4 rounded-2xl font-bold transition-all ${theme.btnSecondary}`}
                >
                    Salir
                </button>
            </div>
        </div>
    );
  }

  const SummaryView = () => {
      const [tension, setTension] = useState(5);
      const [comfort, setComfort] = useState<'Fácil' | 'Media' | 'Difícil'>('Media');

      const handleSave = () => {
          const record: SessionRecord = {
              id: Date.now().toString(),
              date: new Date().toISOString(),
              config,
              totalTime: config.duration === 'free' ? Math.max(1, Math.floor(accumulatedTimeRef.current / 60)) : config.duration,
              tension,
              comfort
          };
          saveHistory(record);
          setScreen(Screen.SETUP);
      };

      return (
          <div className={`max-w-md mx-auto min-h-screen flex flex-col items-center justify-center p-6 space-y-12 text-center animate-in zoom-in-95 duration-500 ${theme.bg}`}>
              <div className="space-y-2">
                  <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-full flex items-center justify-center mx-auto mb-4">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                      </svg>
                  </div>
                  <h2 className={`text-3xl font-bold ${theme.textMain}`}>¡Bien hecho!</h2>
                  <p className={theme.textDim}>Sesión completada con éxito.</p>
              </div>

              <div className={`w-full space-y-8 ${theme.card} p-8 rounded-3xl border shadow-xl`}>
                  <div>
                      <label className={`block text-sm font-medium ${theme.textMain} mb-4`}>¿Cómo calificarías tu tensión actual?</label>
                      <input 
                        type="range" min="0" max="10" value={tension} 
                        onChange={e => setTension(parseInt(e.target.value))}
                        className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-600"
                      />
                      <div className="flex justify-between text-[10px] font-bold uppercase text-slate-500 mt-2">
                          <span>Relajado</span>
                          <span className="text-blue-600 text-sm">{tension}</span>
                          <span>Tenso</span>
                      </div>
                  </div>

                  <div>
                      <label className={`block text-sm font-medium ${theme.textMain} mb-4`}>¿Qué tan fácil fue seguir el ritmo?</label>
                      <div className="flex gap-2">
                          {['Fácil', 'Media', 'Difícil'].map(opt => (
                              <button
                                key={opt}
                                onClick={() => setComfort(opt as any)}
                                className={`flex-1 py-3 rounded-xl border-2 transition-all ${
                                    comfort === opt 
                                    ? 'border-blue-600 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-bold' 
                                    : `${theme.card} ${theme.textDim}`
                                }`}
                              >
                                  {opt}
                              </button>
                          ))}
                      </div>
                  </div>

                  <button 
                    onClick={handleSave}
                    className="w-full py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-xl shadow-blue-500/20 hover:bg-blue-700 active:scale-95 transition-all"
                  >
                      Guardar y Finalizar
                  </button>
              </div>
          </div>
      );
  }

  // Sub-component for logic visualization
  const BreathingCircle = () => {
    const rampFactor = cycleCount < 3 ? 0.8 + (cycleCount * 0.06) : 1.0;
    const currentScale = phase === Phase.INHALE 
        ? 0.5 + (0.5 * config.amplitude * rampFactor * progress)
        : phase === Phase.EXHALE
        ? 0.5 + (0.5 * config.amplitude * rampFactor * (1 - progress))
        : 0.5;

    return (
        <div 
          className="relative flex items-center justify-center transition-transform duration-100 will-change-transform" 
          style={{ transform: `scale(${currentScale})` }}
        >
            <div className="w-64 h-64 bg-blue-600 rounded-full shadow-[0_0_60px_rgba(37,99,235,0.4)] flex items-center justify-center border-4 border-blue-400/30">
                <span className="text-white font-bold uppercase tracking-widest text-xl drop-shadow-md">
                    {phase === Phase.INHALE ? 'Inhala' : phase === Phase.EXHALE ? 'Exhala' : 'Pausa'}
                </span>
            </div>
            <div className="absolute w-72 h-72 bg-blue-400 rounded-full opacity-10 animate-ping"></div>
        </div>
    );
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${theme.bg}`}>
      <main className="container mx-auto max-w-4xl min-h-screen">
        {screen === Screen.SETUP && <SetupView />}
        {screen === Screen.CALIBRATION && <CalibrationView />}
        {screen === Screen.SESSION && <SessionView />}
        {screen === Screen.SUMMARY && <SummaryView />}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { Screen, Phase, BreathConfig, Preferences, SessionRecord } from './types';
import { BREATH_PRESETS, DURATIONS, MICRO_TIPS } from './constants';
import { audioService } from './services/AudioService';
import WaveCanvas from './components/WaveCanvas';

// --- Helper Components defined outside App to prevent re-mount on every state update ---

const BreathingCircle: React.FC<{ phase: Phase; progress: number; amplitude: number; cycleCount: number }> = ({ phase, progress, amplitude, cycleCount }) => {
  const rampFactor = cycleCount < 3 ? 0.8 + (cycleCount * 0.06) : 1.0;
  const currentScale = phase === Phase.INHALE 
      ? 0.5 + (0.5 * amplitude * rampFactor * progress)
      : phase === Phase.EXHALE
      ? 0.5 + (0.5 * amplitude * rampFactor * (1 - progress))
      : 0.5;

  return (
      <div 
        className="relative flex items-center justify-center transition-transform duration-100 will-change-transform" 
        style={{ transform: `scale(${currentScale})` }}
      >
          <div className="w-64 h-64 bg-blue-600 rounded-full shadow-[0_0_60px_rgba(37,99,235,0.4)] flex items-center justify-center border-4 border-blue-400/30">
              <span className="text-white font-bold uppercase tracking-widest text-xl drop-shadow-md">
                  {phase === Phase.INHALE ? 'Inhala' : phase === Phase.EXHALE ? 'Exhala' : 'Pausa'}
              </span>
          </div>
          <div className="absolute w-72 h-72 bg-blue-400 rounded-full opacity-10 animate-ping"></div>
      </div>
  );
};

const App: React.FC = () => {
  // --- State ---
  const [screen, setScreen] = useState<Screen>(Screen.SETUP);
  const [config, setConfig] = useState<BreathConfig>({
    inhale: 4,
    exhale: 6,
    hold: 0,
    duration: 5,
    amplitude: 0.8
  });
  const [prefs, setPrefs] = useState<Preferences>({
    darkMode: false,
    reduceMotion: false,
    audioVolume: 0.5,
    isMuted: false,
    silentMode: false
  });
  const [history, setHistory] = useState<SessionRecord[]>([]);

  // Runtime Session State
  const [phase, setPhase] = useState<Phase>(Phase.INHALE);
  const [progress, setProgress] = useState(0);
  const [cycleCount, setCycleCount] = useState(0);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [tipIndex, setTipIndex] = useState(0);
  const [isActive, setIsActive] = useState(false);

  // Refs for logic
  const requestRef = useRef<number>(0);
  const lastFrameTimeRef = useRef<number>(0);
  const accumulatedTimeRef = useRef<number>(0);
  const lastSecondEmittedRef = useRef<number>(-1);
  const tipTimerRef = useRef<number>(0);

  // --- Theme Object ---
  const theme = useMemo(() => ({
    bg: prefs.darkMode ? 'bg-slate-950' : 'bg-slate-50',
    card: prefs.darkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100',
    input: prefs.darkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200 text-slate-900',
    textMain: prefs.darkMode ? 'text-slate-100' : 'text-slate-900',
    textDim: prefs.darkMode ? 'text-slate-500' : 'text-slate-400',
    btnSecondary: prefs.darkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200',
  }), [prefs.darkMode]);

  // --- Persistence ---
  useEffect(() => {
    const savedHistory = localStorage.getItem('breath_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
    const savedPrefs = localStorage.getItem('breath_prefs');
    if (savedPrefs) setPrefs(JSON.parse(savedPrefs));
  }, []);

  useEffect(() => {
    localStorage.setItem('breath_prefs', JSON.stringify(prefs));
  }, [prefs]);

  useEffect(() => {
    audioService.updateSettings(prefs.audioVolume, prefs.isMuted, prefs.silentMode);
  }, [prefs.audioVolume, prefs.isMuted, prefs.silentMode]);

  // --- Logic ---

  const stopSession = useCallback(() => {
    setIsActive(false);
    if (requestRef.current) cancelAnimationFrame(requestRef.current);
    setScreen(Screen.SETUP);
  }, []);

  const startSession = (isCalibration: boolean) => {
    setCycleCount(0);
    setPhase(Phase.INHALE);
    setProgress(0);
    setTipIndex(0);
    accumulatedTimeRef.current = 0;
    lastFrameTimeRef.current = 0;
    lastSecondEmittedRef.current = -1;
    tipTimerRef.current = 0;

    if (isCalibration) {
      setTimeLeft(30);
      setScreen(Screen.CALIBRATION);
    } else {
      setTimeLeft(config.duration === 'free' ? 0 : config.duration * 60);
      setScreen(Screen.SESSION);
    }
    setIsActive(true);
  };

  const update = useCallback((time: number) => {
    if (!isActive) {
      lastFrameTimeRef.current = 0;
      return;
    }

    if (!lastFrameTimeRef.current) {
      lastFrameTimeRef.current = time;
    }

    const deltaTime = (time - lastFrameTimeRef.current) / 1000;
    lastFrameTimeRef.current = time;
    accumulatedTimeRef.current += deltaTime;

    const elapsedTotal = accumulatedTimeRef.current;
    const currentSecond = Math.floor(elapsedTotal);

    if (currentSecond > lastSecondEmittedRef.current) {
        lastSecondEmittedRef.current = currentSecond;
        audioService.playClick();

        if (screen === Screen.CALIBRATION || (screen === Screen.SESSION && config.duration !== 'free')) {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    setIsActive(false);
                    return 0;
                }
                return prev - 1;
            });
        }

        tipTimerRef.current += 1;
        if (tipTimerRef.current >= 15) {
            tipTimerRef.current = 0;
            setTipIndex(prev => (prev + 1) % MICRO_TIPS.length);
        }
    }

    const cycleTime = config.inhale + config.exhale + config.hold;
    const timeInCycle = elapsedTotal % cycleTime;
    const cycleIdx = Math.floor(elapsedTotal / cycleTime);

    let nextPhase = Phase.INHALE;
    let nextProgress = 0;

    if (timeInCycle < config.inhale) {
      nextPhase = Phase.INHALE;
      nextProgress = timeInCycle / config.inhale;
    } else if (timeInCycle < config.inhale + config.exhale) {
      nextPhase = Phase.EXHALE;
      nextProgress = (timeInCycle - config.inhale) / config.exhale;
    } else {
      nextPhase = Phase.HOLD;
      nextProgress = (timeInCycle - config.inhale - config.exhale) / config.hold;
    }

    setPhase(nextPhase);
    setProgress(nextProgress);
    setCycleCount(cycleIdx);

    requestRef.current = requestAnimationFrame(update);
  }, [isActive, config, screen]);

  useEffect(() => {
    if (isActive) {
      requestRef.current = requestAnimationFrame(update);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (timeLeft === 0 && screen === Screen.SESSION && accumulatedTimeRef.current > 0) {
          setScreen(Screen.SUMMARY);
      }
    }
    return () => { if (requestRef.current) cancelAnimationFrame(requestRef.current); };
  }, [isActive, update, timeLeft, screen]);

  // --- Components ---

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60);
      const s = seconds % 60;
      return `${m}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${theme.bg}`}>
      <main className="container mx-auto max-w-4xl min-h-screen">
        {screen === Screen.SETUP && (
          <div className="max-w-xl mx-auto p-6 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <header className="text-center">
              <h1 className={`text-4xl font-bold tracking-tight ${theme.textMain}`}>MindfulBreather</h1>
              <p className={`${theme.textDim} mt-2`}>Encuentra tu centro, respira con calma.</p>
            </header>

            <section>
              <h2 className="text-xs font-semibold uppercase tracking-wider text-slate-500 mb-4">Objetivo</h2>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                {BREATH_PRESETS.map(p => {
                  const isSelected = config.inhale === p.inhale && config.exhale === p.exhale && config.hold === p.hold;
                  return (
                    <button key={p.id} onClick={() => setConfig({...config, ...p})} className={`py-3 px-2 rounded-xl text-sm font-medium transition-all ${isSelected ? 'bg-blue-600 text-white shadow-xl scale-105' : `${theme.card} ${theme.textDim} border hover:border-blue-400`}`}>
                      {p.name}
                      <div className="text-[10px] opacity-70">{p.inhale}/{p.exhale}/{p.hold}</div>
                    </button>
                  );
                })}
              </div>
            </section>

            <section className={`${theme.card} p-6 rounded-3xl border shadow-sm space-y-6`}>
              <div className="grid grid-cols-3 gap-4">
                {['inhale', 'exhale', 'hold'].map((key) => (
                  <div key={key} className="text-center">
                    <label className="block text-[10px] uppercase font-bold text-slate-500 mb-1">{key === 'inhale' ? 'Inhala' : key === 'exhale' ? 'Exhala' : 'Pausa'}</label>
                    <input type="number" step="0.5" value={config[key as keyof BreathConfig] as number} onChange={e => setConfig({...config, [key]: parseFloat(e.target.value) || 0})} className={`w-full ${theme.input} rounded-lg p-2 text-center font-bold border`} />
                  </div>
                ))}
              </div>
              <div>
                <label className="flex justify-between text-sm text-slate-500 mb-2"><span>Amplitud</span><span className="font-bold">{Math.round(config.amplitude * 100)}%</span></label>
                <input type="range" min="0.5" max="1" step="0.05" value={config.amplitude} onChange={e => setConfig({...config, amplitude: parseFloat(e.target.value)})} className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-600" />
              </div>
              <div>
                <label className="block text-sm text-slate-500 mb-2">Duración (minutos)</label>
                <div className="flex gap-2">
                  {DURATIONS.map(d => (
                    <button key={d} onClick={() => setConfig({...config, duration: d as any})} className={`flex-1 py-2 rounded-lg text-sm transition-colors ${config.duration === d ? 'bg-slate-800 dark:bg-slate-100 text-white dark:text-slate-900 font-bold' : `${theme.btnSecondary}`}`}>
                      {d === 'free' ? 'Libre' : d}
                    </button>
                  ))}
                </div>
              </div>
            </section>

            <section className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-4 px-2">
                <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
                  <input type="checkbox" checked={prefs.darkMode} onChange={e => setPrefs({...prefs, darkMode: e.target.checked})} className="rounded" />
                  <span>Modo Oscuro</span>
                </label>
                <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
                  <input type="checkbox" checked={prefs.reduceMotion} onChange={e => setPrefs({...prefs, reduceMotion: e.target.checked})} className="rounded" />
                  <span>Reducir Movimiento</span>
                </label>
              </div>
              <div className={`${theme.card} p-4 rounded-2xl border flex flex-col justify-center`}>
                <label className="text-xs text-slate-400 mb-2 flex justify-between"><span>Audio</span><span className="font-bold">{Math.round(prefs.audioVolume * 100)}%</span></label>
                <input type="range" min="0" max="1" step="0.01" value={prefs.audioVolume} onChange={e => setPrefs({...prefs, audioVolume: parseFloat(e.target.value)})} className="w-full accent-blue-600 mb-3" />
                <div className="flex gap-2">
                  <button onClick={() => setPrefs({...prefs, isMuted: !prefs.isMuted})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>{prefs.isMuted ? 'Unmute' : 'Mute'}</button>
                  <button onClick={() => setPrefs({...prefs, silentMode: !prefs.silentMode})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>{prefs.silentMode ? 'Con Click' : 'Silencioso'}</button>
                </div>
              </div>
            </section>

            <div className="flex flex-col sm:flex-row gap-4 pt-4">
              <button onClick={() => startSession(true)} className={`flex-1 py-4 px-6 rounded-2xl border-2 transition-all font-bold ${prefs.darkMode ? 'border-slate-800 text-slate-300 hover:bg-slate-900' : 'border-blue-100 text-blue-600 hover:bg-blue-50'}`}>Calibrar</button>
              <button onClick={() => startSession(false)} className="flex-1 py-4 px-6 rounded-2xl bg-blue-600 text-white font-bold shadow-xl shadow-blue-500/30 hover:bg-blue-700 transition-all hover:scale-[1.02] active:scale-95">Comenzar</button>
            </div>
          </div>
        )}

        {screen === Screen.CALIBRATION && (
          <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center space-y-12">
            <header><h2 className={`text-2xl font-bold ${theme.textMain}`}>Modo Calibración</h2><p className={theme.textDim}>Ajusta el ritmo a tu comodidad.</p></header>
            <BreathingCircle phase={phase} progress={progress} amplitude={config.amplitude} cycleCount={cycleCount} />
            <div className="w-full max-w-md space-y-6">
              <div className={`${theme.card} flex justify-between items-center p-4 rounded-2xl shadow-sm border`}>
                <button onClick={() => { config.inhale *= 1.1; config.exhale *= 1.1; setConfig({...config}); }} className={`px-6 py-3 rounded-xl font-bold ${theme.btnSecondary}`}>Más lento</button>
                <div className={`font-mono text-lg font-bold ${theme.textMain}`}>{config.inhale.toFixed(1)}s / {config.exhale.toFixed(1)}s</div>
                <button onClick={() => { config.inhale *= 0.9; config.exhale *= 0.9; setConfig({...config}); }} className={`px-6 py-3 rounded-xl font-bold ${theme.btnSecondary}`}>Más rápido</button>
              </div>
              <div className="flex gap-4">
