                </div>
              </div>
            </section>

            <section className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-4 px-2">
                <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
                  <input type="checkbox" checked={!prefs.darkMode} onChange={e => setPrefs({...prefs, darkMode: !e.target.checked})} className="rounded" />
                  <span>Modo Día</span>
                </label>
                <label className={`flex items-center space-x-2 text-sm ${theme.textMain} cursor-pointer`}>
                  <input type="checkbox" checked={prefs.reduceMotion} onChange={e => setPrefs({...prefs, reduceMotion: e.target.checked})} className="rounded" />
                  <span>Reducir Movimiento</span>
                </label>
              </div>
              <div className={`${theme.card} p-4 rounded-2xl border flex flex-col justify-center`}>
                <label className="text-xs text-slate-400 mb-2 flex justify-between"><span>Audio</span><span className="font-bold">{Math.round(prefs.audioVolume * 100)}%</span></label>
                <input type="range" min="0" max="1" step="0.01" value={prefs.audioVolume} onChange={e => setPrefs({...prefs, audioVolume: parseFloat(e.target.value)})} className="w-full accent-blue-600 mb-3" />
                <div className="flex gap-2">
                  <button onClick={() => setPrefs({...prefs, isMuted: !prefs.isMuted})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>{prefs.isMuted ? 'Unmute' : 'Mute'}</button>
                  <button onClick={() => setPrefs({...prefs, silentMode: !prefs.silentMode})} className={`flex-1 text-[10px] uppercase font-bold py-2 rounded-lg ${theme.btnSecondary}`}>{prefs.silentMode ? 'Con Click' : 'Silencioso'}</button>
                </div>
              </div>
            </section>

            <div className="flex flex-col sm:flex-row gap-4 pt-4">
              <button onClick={() => startSession(true)} className={`flex-1 py-4 px-6 rounded-2xl border-2 transition-all font-bold ${prefs.darkMode ? 'border-slate-800 text-slate-300 hover:bg-slate-900' : 'border-blue-100 text-blue-600 hover:bg-blue-50'}`}>Calibrar</button>
