    setCycleCount(0);
    setPhase(Phase.INHALE);
    setProgress(0);
    setTipIndex(0);
    accumulatedTimeRef.current = 0;
    lastFrameTimeRef.current = 0;
    lastSecondEmittedRef.current = -1;
